sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    var selector = new x_146833_idpkiro.BuildAgentSelector();
    var agents = selector.getActiveAgents();

    response.setStatus(200);
    response.setBody({
        success: true,
        count: agents.length,
        agents: agents.map(function(a) {
            return {
                sys_id: a.sys_id,
                agent_id: a.agent_id,
                name: a.name,
                provider: a.provider,
                model: a.model,
                context_window: a.context_window,
                quality_score: a.quality_score,
                speed_score: a.speed_score,
                input_cost_per_1k: a.input_cost_per_1k,
                output_cost_per_1k: a.output_cost_per_1k,
                specializations: a.specializations
            };
        })
    });
})(request, response);
